.sidebar-metadata-field {
  gap: 4px;
}

.sidebar-metadata-field span {
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-xs);
  text-transform: uppercase;
}

.sidebar-metadata-field select,
.sidebar-metadata-field input {
  min-height: 34px;
  border-radius: var(--relay-radius-sm);
  background: rgb(0 0 0 / 14%);
}

.detail-actions {
  margin-top: var(--relay-space-3);
}

.ticket-detail-actions-row {
  margin: 0;
  padding: 0 var(--relay-space-3) var(--relay-space-3);
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.ticket-markdown-tabs {
  min-width: 0;
  display: flex;
  flex: 0 0 auto;
  flex-direction: column;
  min-height: 0;
