}

.ticket-markdown-tablist {
  width: max-content;
  max-width: 100%;
  display: inline-flex;
  gap: 4px;
  border-radius: var(--relay-radius-sm);
  background: rgb(0 0 0 / 18%);
  padding: 4px;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.ticket-markdown-tab {
  min-height: 30px;
  border-radius: var(--relay-radius-sm);
  background: transparent;
  padding: 0 12px;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  font-weight: 560;
}

.ticket-markdown-tab:hover,
.ticket-markdown-tab.active {
  background: rgb(255 255 255 / 8%);
  color: var(--relay-text);
  transform: none;
}

.ticket-markdown-tab-panel {
  min-width: 0;
  min-height: 0;
  margin-top: var(--relay-space-3);
}

.ticket-markdown-preview-panel {
  display: grid;
  grid-template-rows: minmax(0, 1fr) auto;
  overflow: hidden;
}

.ticket-markdown-preview-panel.collapsed {
  height: min(340px, 52dvh);
